      },
      {
        "name": "Notification Router",
        "responsibility": "Consumes delivery domain events from the queue, resolves customer notification preferences (email, SMS, or both), and dispatches to channel-specific workers.",
        "boundaries": "Owns notification preference lookups and channel routing logic. Does not own delivery state or provider-specific formatting."
      },
      {
        "name": "Channel Workers (Email, SMS, future: Push, WhatsApp)",
        "responsibility": "Each worker handles one channel: formats the message for that channel's provider API, calls the provider, and reports success/failure back to the queue for retry.",
        "boundaries": "Each worker is independently deployable and independently retryable. Provider-specific logic (Twilio, SendGrid, etc.) is encapsulated here."
      },
      {
        "name": "Message Queue",
        "responsibility": "Durable message storage with at-least-once delivery, dead-letter queue for poison messages, and visibility timeout for retry coordination.",
        "boundaries": "Managed service (SQS, Pub/Sub) or lightweight library (pg-boss on existing Postgres). The team does NOT operate broker infrastructure."
      },
      {
        "name": "Dead Letter Queue + Alert",
        "responsibility": "Captures notifications that exhausted all retry attempts. Triggers an alert to the ops team so no notification is silently dropped.",
        "boundaries": "Terminal failure boundary. Human intervention path."
      }
    ],
    "interfaces": [
      {
        "from": "Delivery Service",
        "to": "Message Queue",
        "contract": "Publishes DeliveryStatusChanged event: { deliveryId, customerId, status, timestamp, metadata }",
        "coupling_type": "loose — fire-and-forget via queue; delivery service does not wait for notification outcome"
      },
      {
        "from": "Message Queue",
        "to": "Notification Router",
        "contract": "Router subscribes to delivery event topic/queue. Pulls messages, resolves preferences, re-publishes per-channel dispatch messages.",
        "coupling_type": "loose — queue-mediated, at-least-once delivery"
      },
      {
        "from": "Notification Router",
        "to": "Channel Workers",
        "contract": "Publishes channel-specific messages: { channel, recipientAddress, templateId, templateData, attemptCount }",
        "coupling_type": "loose — separate queue per channel enables independent scaling and retry"
      },
      {
        "from": "Channel Workers",
        "to": "External Providers (Twilio, SendGrid, etc.)",
        "contract": "REST/SDK calls to provider APIs. Workers own the provider-specific request/response mapping.",
        "coupling_type": "tight to provider API (unavoidable) — isolated behind channel worker boundary"
      },
      {
        "from": "Message Queue",
        "to": "Dead Letter Queue + Alert",
        "contract": "Messages exceeding maxRetries are moved to DLQ. Alert fires on DLQ depth > 0.",
        "coupling_type": "operational coupling — requires monitoring but no code changes"
      }
    ],
    "data_flow": "1. Delivery Service updates delivery status → publishes DeliveryStatusChanged to queue. 2. Notification Router consumes event → looks up customer preferences → publishes per-channel dispatch messages. 3. Channel Workers consume dispatch messages → format and call provider APIs. 4. On success: message acknowledged and removed. On failure: message returns to queue after visibility timeout for retry with exponential backoff. 5. After max retries exhausted: message moves to DLQ, alert fires.",
    "patterns_used": [
      {
        "pattern": "Domain Events via Message Queue",
        "rationale": "The delivery service's concern is deliveries, not notifications. Publishing a domain event (DeliveryStatusChanged) preserves this separation. The 5-minute latency tolerance makes async processing natural — there is zero benefit to synchronous calls here."
      },
      {
        "pattern": "Competing Consumers",
        "rationale": "Multiple instances of each channel worker can consume from the same queue. This provides horizontal scalability if volume grows, without architectural changes. For a small team, start with 1 worker per channel."
