      {
        "pattern": "Exponential Backoff with Jitter",
        "rationale": "Provider APIs have rate limits and transient failures. Exponential backoff is the standard retry strategy. Managed queues support this natively via visibility timeout configuration."
      },
      {
        "pattern": "Idempotent Message Processing",
        "rationale": "At-least-once delivery means duplicate messages are possible. Each channel worker must be idempotent — use a notification ID to deduplicate. This prevents customers receiving duplicate SMS/emails."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Delivery",
        "classification": "core",
        "aggregates": ["Delivery (root: deliveryId, states: created → picked_up → in_transit → delivered | failed)"]
      },
      {
        "name": "Notification",
        "classification": "supporting",
        "aggregates": ["NotificationRequest (root: notificationId, tracks: channel, recipient, status, attemptCount)", "CustomerPreference (root: customerId, tracks: preferred channels, contact addresses, opt-out flags)"]
