    "context_map": [
      {
        "upstream": "Delivery",
        "downstream": "Notification",
        "relationship": "Customer-Supplier via Domain Events. Delivery context publishes events; Notification context subscribes. Delivery context does not know or care about Notification context. Notification context conforms to the event schema but owns its own internal model."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Option B (event-driven) over Option A (synchronous REST)",
      "gains": "Delivery service stays focused on deliveries — no notification logic polluting the critical path. Retry is handled by queue infrastructure, not application code. Adding a channel requires only a new worker, not modifying existing code. Failed notifications are captured in DLQ, satisfying the reliability requirement natively.",
      "sacrifices": "Introduces a queue dependency — one more piece of infrastructure. Slightly more complex local development and testing setup. Eventual consistency means the delivery service doesn't know if a notification succeeded (acceptable given requirements).",
      "alternatives_considered": ["Option A: Synchronous REST — simpler initially but creates tight coupling, requires custom retry logic in the delivery service, and every new channel modifies the delivery path. Rejected because the latency tolerance eliminates the only advantage of sync calls, while reliability and extensibility requirements directly favor async."]
    },
    {
      "decision": "Managed queue service (SQS/Pub/Sub) over self-hosted broker (RabbitMQ/Kafka)",
      "gains": "Zero operational burden for a 3-person team. Built-in DLQ, retry, monitoring. Pay-per-message pricing is near-free at courier-company scale.",
      "sacrifices": "Vendor lock-in to cloud provider. Less control over broker configuration. Slightly higher per-message latency vs self-hosted (irrelevant given 5-minute tolerance).",
      "alternatives_considered": ["pg-boss (Postgres-backed job queue) — viable if the team already runs Postgres and wants to avoid adding a new service. Trade-off: less battle-tested DLQ behavior, queue polling adds DB load. Good stepping stone.", "RabbitMQ — powerful but requires operational expertise the small team likely lacks. Rejected.", "Kafka — massive overkill for this scale and team size. Rejected."]
    },
    {
      "decision": "Separate queue per channel vs single queue with channel routing",
      "gains": "Independent retry policies per channel (SMS retries may differ from email). One slow provider doesn't block others. Independent scaling per channel.",
      "sacrifices": "More queues to configure (minor with managed services). Slightly more complex routing logic in Notification Router.",
      "alternatives_considered": ["Single queue with all channels — simpler but a Twilio outage would cause backpressure affecting email delivery too. Rejected for violating the reliability requirement."]
    }
  ],

  "flexibility_points": [
    {
      "area": "Adding new notification channels",
      "evolution_path": "Create a new Channel Worker that subscribes to a new per-channel queue. Update the Notification Router to include the new channel in its routing logic. No changes to the Delivery Service or existing workers. Estimated effort: 1-2 days per channel."
    },
    {
      "area": "Swapping notification providers",
      "evolution_path": "Replace the provider-specific code inside a Channel Worker. The queue contract and message format remain unchanged. Zero impact on other components."
    },
    {
      "area": "Notification templates and formatting",
      "evolution_path": "Template logic lives inside Channel Workers. Can evolve from hardcoded strings → template files → template service without affecting the event pipeline."
    },
    {
      "area": "Scaling individual channels",
      "evolution_path": "Increase worker count for a specific channel's queue. No code changes, no architectural changes. Competing consumers pattern handles this natively."
    }
  ],

